#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int a[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        int max = 0;
        for (int i = 0; i < n; i++) {
            int temp = a[i];
            a[i] = 9;
            int num = 0;
            for (int j = 0; j < n; j++) {
                num = num * 10 + a[j];
            }
            if (num > max) {
                max = num;
            }
            a[i] = temp;
        }
        printf("%d\n", max);
    }
    return 0;
}

