        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = scanner.nextInt();
            }
            int max = 0;
            for (int i = 0; i < n; i++) {
                int temp = a[i];
                a[i] = 9;
                int num = 0;
                for (int j = 0; j < n; j++) {
                    num = num * 10 + a[j];
                }
                if (num > max) {
                    max = num;
                }
                a[i] = temp;
            }
            System.out.println(max);
        }
    }
